// Group executions by workflow, calculate health metrics
const response = $input.all()[0].json;
const executions = response.body?.data || response.body || [];

const byWorkflow = {};

for (const exec of executions) {
  const wfId = exec.workflowId || 'unknown';
  const wfName = exec.workflowName || exec.workflowId || 'unknown';

  if (!byWorkflow[wfId]) {
    byWorkflow[wfId] = {
      workflow_id: wfId,
      workflow_name: wfName,
      total_executions: 0,
      success_count: 0,
      error_count: 0,
      waiting_count: 0
    };
  }

  byWorkflow[wfId].total_executions++;

  if (exec.status === 'success' || exec.finished === true) {
    byWorkflow[wfId].success_count++;
  } else if (exec.status === 'error' || exec.status === 'crashed') {
    byWorkflow[wfId].error_count++;
  } else {
    byWorkflow[wfId].waiting_count++;
  }
}

// Calculate error rates and build output
const results = Object.values(byWorkflow).map(wf => {
  const error_rate = wf.total_executions > 0
    ? Math.round((wf.error_count / wf.total_executions) * 10000) / 100
    : 0;
  return {
    ...wf,
    error_rate,
    has_high_error_rate: error_rate > 10
  };
});

return results.map(r => ({ json: r }));

