// Build alert for high error rate workflows
const wf = $('Calculate Per-Workflow Metrics').item.json;
return [{ json: {
  alert_type: 'workflow_health',
  alert_title: `Workflow Error Rate Alert: ${wf.workflow_name}`,
  alert_body: `<p>Workflow <strong>${wf.workflow_name}</strong> (${wf.workflow_id}) has an error rate of <strong>${wf.error_rate}%</strong> over the last 250 executions.</p><p>Total: ${wf.total_executions} | Success: ${wf.success_count} | Errors: ${wf.error_count}</p>`,
  severity: wf.error_rate > 25 ? 'critical' : 'warning',
  source_workflow: 'TG-123',
  metadata: JSON.stringify(wf)
} }];
